from collections import Counter

def char_frequency(s: str) -> dict[str, int]:
    return dict(Counter(s))


# Manual approach (no imports)
def char_frequency_manual(s: str) -> dict[str, int]:
    freq = {}
    for char in s:
        freq[char] = freq.get(char, 0) + 1
    return freq


# Example usage
print(char_frequency("hello"))
# Output: {'h': 1, 'e': 1, 'l': 2, 'o': 1}

def largest_number(n: int) -> int:
    digits = sorted(str(n), reverse=True)
    return int(''.join(digits))


# Example usage
print(largest_number(38294))   # Output: 98432
print(largest_number(10523))   # Output: 53210

def average_price(prices: list[float]) -> float | None:
    if not prices:
        return None
    return sum(prices) / len(prices)


# Example usage
print(average_price([12.99, 9.99, 24.50, 7.99]))
# Output: 13.8675

print(average_price([]))
# Output: None
